<!-- Кнопка "Наверх" с дополнительными эффектами -->
<button id="backToTop" class="fixed bottom-6 right-6 z-50 w-12 h-12 rounded-full bg-gradient-to-br from-white/10 to-white/5 backdrop-blur-md border border-white/20 text-white flex items-center justify-center cursor-pointer transition-all duration-300 opacity-0 invisible hover:bg-gradient-to-br hover:from-[#ff1a2a]/80 hover:to-[#51080d]/80 hover:scale-110 hover:border-[#ff1a2a]/50 shadow-lg group">
    <svg class="w-5 h-5 group-hover:-translate-y-1 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24">
        <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M5 10l7-7m0 0l7 7m-7-7v18"/>
    </svg>
    <!-- Маленькая пульсирующая точка -->
    <span class="absolute -top-1 -right-1 w-2 h-2 bg-[#ff1a2a] rounded-full animate-pulse"></span>
</button>